def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / cap
        base_priority = 0
        penalty = 0
        bonus = 0
        if usage_ratio > 2:
            base_priority = 2000 * usage_ratio
            penalty += 100
        elif usage_ratio > 1:
            base_priority = 1500 * usage_ratio
            penalty += 50
        elif usage_ratio == 1:
            base_priority = 20
        elif usage_ratio > 0.5:
            base_priority = (1 - usage_ratio) * 100
            penalty -= 20
        else:
            try:
                val = np.log(1 - usage_ratio + 1e-10)
            except:
                val = -100
            if val < -2:
                base_priority = -val * 10
            else:
                base_priority = -val * 3
        if cap < 0.05:
            penalty += 80
        elif cap < 0.1:
            penalty += 40
        elif cap < 0.5:
            penalty += 15
        for j in range(len(bins)):
            if j == i:
                continue
            diff = abs(cap - bins[j])
            if diff < 0.05:
                bonus += 5
            elif diff > 1:
                penalty += 2
        if usage_ratio < 0.3 and cap > 5:
            bonus += 20
        priorities[i] = base_priority + penalty - bonus
    min_val = np.min(priorities[np.isfinite(priorities)])
    if min_val < 0:
        priorities = priorities - min_val + 1
    priorities[np.isnan(priorities)] = np.inf
    return priorities
